def username_encrypt(username: str) -> str:
    """
    Encrypt username according to srun3k-new.html.
    Shift each ASCII code by +4 and prepend {SRUN3}\r\n.
    """
    username_crypto = ""
    for char in username:
        username_crypto += chr(ord(char) + 4)
    return "{SRUN3}\r\n" + username_crypto


def gen_jQuery(jQuery_version: str) -> str:
    return "jQuery" + re.sub(r"\D", "", jQuery_version) + str(random())[2:]


def password_encrypt(raw_password: str, token: str) -> str:
    return hmac.new(token.encode(), raw_password.encode(), hashlib.md5).hexdigest()


def gen_info(token: str, username: str, password: str, ip: str, ac_id: str) -> str:
    info = json.dumps(
        {
            "username": username,
            "password": password,
            "ip": ip,
            "acid": ac_id,
            "enc_ver": "srun_bx1",
        },
        separators=(",", ":"),
    )
    return "{SRBX1}" + CustomBase64(
        "LVoJPiCN2R8G90yg+hmFHuacZ1OWMnrsSTXkYpUq/3dlbfKwv6xztjI7DeBE45QA"
    ).encode(xEncode(info, token).encode("iso-8859-1"))


def gen_chksum(
    token: str,
    username: str,
    hmd5_password: str,
    ac_id: str,
    ip: str,
    n: str,
    type_: str,
    info: str,
) -> str:
    chkstr = (
        token
        + username
        + token
        + hmd5_password
        + token
        + ac_id
        + token
        + ip
        + token
        + n
        + token
        + type_
        + token
        + info
    )
    return hashlib.sha1(chkstr.encode()).hexdigest()


def show_data_usage(data: int) -> str:
    if data < 1024:
        return f"{data} Bytes"
    elif data < 1024 * 1024:
        return "%.2f KiB" % (data / 1024)
    elif data < 1024 * 1024 * 1024:
        return "%.2f MiB" % (data / 1024 / 1024)
    else:
        return "%.2f GiB" % (data / 1024 / 1024 / 1024)


def show_time_formatted(seconds: int) -> str:
    minutes = seconds // 60
    hours = minutes // 60
    days = hours // 24
    if minutes <= 0:
        return f"{seconds} Seconds"
    elif hours <= 0:
        return f"{minutes} Minutes {seconds % 60} Seconds"
    elif days <= 0:
        return f"{hours} Hours {minutes % 60} Minutes {seconds % 60} Seconds"
    else:
        return f"{days} Days {hours % 24} Hours {minutes % 60} Minutes {seconds % 60} Seconds"


def log_info(*msg: str):
    print(f"[{datetime.now().strftime('%H:%M:%S')}]", *msg)


def log_warning(*msg: str):
    print(
        Fore.YELLOW + f"[{datetime.now().strftime('%H:%M:%S')}]", *msg, Style.RESET_ALL
    )


def log_error(*msg: str):
    print(Fore.RED + f"[{datetime.now().strftime('%H:%M:%S')}]", *msg, Style.RESET_ALL)


def log_debug(*msg: str):
    print(Style.DIM + f"[{datetime.now().strftime('%H:%M:%S')}]", *msg, Style.RESET_ALL)


def log_custom(color: str, *msg: str):
    print(color + f"[{datetime.now().strftime('%H:%M:%S')}]", *msg, Style.RESET_ALL)
